import React, { useState, useEffect, useRef, useCallback } from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import { useAuth } from '../../contexts/AuthContext';
import { useUI } from '../../contexts/UIContext';
import { notifAPI, exchangeAPI } from '../../services/api';
import { formatRupiah } from '../../utils/format';
import toast from 'react-hot-toast';
import {
  Home, Users, FileText, Package, CreditCard, ClipboardList,
  DollarSign, Truck, FolderOpen, BarChart3, Receipt, TrendingUp,
  BookOpen, Globe, LogOut, Bell, Menu, User,
  ChevronDown, Building2, Shield, GitBranch, Moon, Sun, Languages,
  PanelLeftClose, PanelLeftOpen, X, Settings, Zap, Search,
  Import, ArrowUpRight, Activity, ChevronRight, Layers, Key
} from 'lucide-react';

// ── Menu Configuration ────────────────────────────────────────
const NAV_GROUPS = [
  {
    label: 'Overview',
    items: [
      { path: '/dashboard', icon: Home, label: 'Dashboard', roles: ['super_admin','general_manager','sales_manager','sales','finance'] },
      { path: '/analytics', icon: TrendingUp, label: 'Analitik', roles: ['super_admin','general_manager','sales_manager'] },
    ]
  },
  {
    label: 'CRM',
    items: [
      { path: '/customers', icon: Users, label: 'Customer 360', roles: ['super_admin','general_manager','sales_manager','sales'] },
      { path: '/pipeline', icon: GitBranch, label: 'Pipeline', roles: ['super_admin','general_manager','sales_manager','sales'] },
      { path: '/products', icon: Package, label: 'Produk', roles: ['super_admin','general_manager','sales_manager','sales'] },
    ]
  },
  {
    label: 'Transaksi',
    items: [
      { path: '/invoices', icon: FileText, label: 'Invoice', roles: ['super_admin','general_manager','sales_manager','sales','finance'] },
      { path: '/payments', icon: CreditCard, label: 'Pembayaran', roles: ['super_admin','general_manager','sales_manager','sales','finance'] },
      { path: '/payment-requests', icon: ClipboardList, label: 'Approval Pelunasan', roles: ['super_admin','general_manager','sales_manager','sales','finance'] },
      { path: '/commissions', icon: DollarSign, label: 'Sales Incentive', roles: ['super_admin','general_manager','sales_manager','sales','finance'] },
    ]
  },
  {
    label: 'Operasional',
    items: [
      { path: '/import-export', icon: Import, label: 'Import / Export', roles: ['super_admin','general_manager','sales_manager','finance'] },
      { path: '/shipments', icon: Truck, label: 'Pengiriman', roles: ['super_admin','general_manager','sales_manager','sales','finance'] },
      { path: '/documents', icon: FolderOpen, label: 'Dokumen', roles: ['super_admin','general_manager','sales_manager','sales','finance'] },
    ]
  },
  {
    label: 'Keuangan',
    items: [
      { path: '/finance', icon: BarChart3, label: 'Keuangan', roles: ['super_admin','general_manager','finance'] },
      { path: '/tax-reports', icon: Receipt, label: 'Laporan Pajak', roles: ['super_admin','general_manager','finance'] },
    ]
  },
  {
    label: 'Sistem',
    items: [
      { path: '/knowledge-base', icon: BookOpen, label: 'Content Center', roles: ['super_admin','general_manager','sales_manager','sales','finance'] },
      { path: '/users', icon: Settings, label: 'Kelola User', roles: ['super_admin'] },
    ]
  }
];

const ROLE_COLORS = {
  super_admin: { bg: 'bg-purple-500', text: 'text-purple-500', label: 'Super Admin' },
  general_manager: { bg: 'bg-blue-500', text: 'text-blue-500', label: 'General Manager' },
  sales_manager: { bg: 'bg-cyan-500', text: 'text-cyan-500', label: 'Sales Manager' },
  sales: { bg: 'bg-green-500', text: 'text-green-500', label: 'Sales' },
  finance: { bg: 'bg-amber-500', text: 'text-amber-500', label: 'Finance' },
};

function getInitials(name = '') {
  return name.split(' ').map(w => w[0]).slice(0, 2).join('').toUpperCase();
}

// ── Sidebar Component ─────────────────────────────────────────
function Sidebar({ user, collapsed, onCollapse, mobileOpen, onMobileClose, location, onLogout }) {
  const navigate = useNavigate();
  const role = user?.role;

  const filteredGroups = NAV_GROUPS.map(group => ({
    ...group,
    items: group.items.filter(item => item.roles.includes(role))
  })).filter(g => g.items.length > 0);

  return (
    <>
      {/* Mobile Overlay */}
      {mobileOpen && (
        <div
          className="fixed inset-0 bg-black/50 backdrop-blur-sm z-20 lg:hidden"
          onClick={onMobileClose}
        />
      )}

      <aside
        style={{
          width: collapsed ? 'var(--sidebar-collapsed)' : 'var(--sidebar-width)',
          transition: 'width 300ms cubic-bezier(0.4,0,0.2,1)',
          zIndex: 30
        }}
        className={`
          sidebar flex flex-col h-screen flex-shrink-0
          fixed lg:static inset-y-0 left-0
          ${mobileOpen ? 'translate-x-0' : '-translate-x-full lg:translate-x-0'}
          transition-transform lg:transition-[width] duration-300
        `}
      >
        {/* Logo Area */}
        <div className={`flex items-center border-b border-white/5 flex-shrink-0 ${collapsed ? 'justify-center p-4' : 'gap-3 px-5 py-5'}`}>
          <div
            className="w-9 h-9 rounded-xl flex items-center justify-center flex-shrink-0 cursor-pointer"
            style={{ background: 'linear-gradient(135deg, #3a71f6, #1a3dd8)' }}
            onClick={() => navigate('/dashboard')}
          >
            <Layers className="w-4.5 h-4.5 text-white" style={{width:18,height:18}} />
          </div>
          {!collapsed && (
            <div className="min-w-0">
              <div className="text-white font-bold text-sm tracking-tight leading-none">Abnan CRM</div>
              <div className="text-xs mt-0.5" style={{ color: 'rgba(255,255,255,0.35)', fontSize: 10, fontWeight: 600, letterSpacing: '0.06em' }}>
                ENTERPRISE SUITE
              </div>
            </div>
          )}
          <button
            onClick={onMobileClose}
            className="lg:hidden ml-auto p-1 rounded-lg text-white/40 hover:text-white hover:bg-white/10 transition-all"
          >
            <X className="w-4 h-4" />
          </button>
        </div>

        {/* Nav */}
        <nav className="flex-1 overflow-y-auto py-4 px-2" style={{ scrollbarWidth: 'none' }}>
          {filteredGroups.map((group, gi) => (
            <div key={gi} className="mb-1">
              {!collapsed && (
                <div className="sidebar-section-label">{group.label}</div>
              )}
              {group.items.map(item => {
                const Icon = item.icon;
                const isActive = location.pathname === item.path || location.pathname.startsWith(item.path + '/');
                return (
                  <Link
                    key={item.path}
                    to={item.path}
                    onClick={onMobileClose}
                    title={collapsed ? item.label : undefined}
                    className={`sidebar-item ${isActive ? 'active' : ''} ${collapsed ? 'justify-center' : ''}`}
                    style={{ marginBottom: 2 }}
                  >
                    <Icon style={{ width: 16, height: 16, flexShrink: 0 }} />
                    {!collapsed && <span className="flex-1 truncate">{item.label}</span>}
                    {!collapsed && isActive && <ChevronRight style={{ width: 12, height: 12, opacity: 0.5 }} />}
                  </Link>
                );
              })}
            </div>
          ))}
        </nav>

        {/* Bottom: User Card */}
        {!collapsed ? (
          <div className="p-3 border-t border-white/5 flex-shrink-0">
            <Link to="/profile" className="flex items-center gap-3 p-2.5 rounded-xl hover:bg-white/6 transition-all cursor-pointer group" style={{ textDecoration: 'none', background: 'rgba(255,255,255,0.05)' }}>
              <div className="w-8 h-8 rounded-lg flex items-center justify-center text-white text-xs font-bold flex-shrink-0"
                style={{ background: 'linear-gradient(135deg, #3a71f6, #7c3aed)' }}>
                {getInitials(user?.full_name)}
              </div>
              <div className="flex-1 min-w-0">
                <div className="text-white text-xs font-semibold truncate leading-tight">{user?.full_name}</div>
                <div className="text-xs truncate mt-0.5" style={{ color: 'rgba(255,255,255,0.35)', fontSize: 10 }}>
                  {ROLE_COLORS[role]?.label || role}
                </div>
              </div>
              <ArrowUpRight style={{ width: 12, height: 12, color: 'rgba(255,255,255,0.3)', flexShrink: 0 }} />
            </Link>
          </div>
        ) : (
          <div className="p-3 border-t border-white/5 flex-shrink-0 flex justify-center">
            <div className="w-8 h-8 rounded-lg flex items-center justify-center text-white text-xs font-bold"
              style={{ background: 'linear-gradient(135deg, #3a71f6, #7c3aed)' }}>
              {getInitials(user?.full_name)}
            </div>
          </div>
        )}
      </aside>
    </>
  );
}

// ── Profile Dropdown ──────────────────────────────────────────
function ProfileDropdown({ user, onLogout, onClose, rates }) {
  const navigate = useNavigate();
  const { theme, toggleTheme, locale, setLocale } = useUI();
  const role = user?.role;
  const roleInfo = ROLE_COLORS[role] || {};

  return (
    <div
      className="dropdown-menu"
      style={{ width: 280, position: 'absolute', right: 0, top: 'calc(100% + 8px)', zIndex: 100 }}
      onClick={e => e.stopPropagation()}
    >
      {/* User Info Header */}
      <div className="p-4 border-b" style={{ borderColor: 'var(--border-base)' }}>
        <div className="flex items-center gap-3">
          <div className="w-12 h-12 rounded-xl flex items-center justify-center text-white font-bold text-sm flex-shrink-0"
            style={{ background: 'linear-gradient(135deg, #3a71f6, #7c3aed)' }}>
            {getInitials(user?.full_name)}
          </div>
          <div className="flex-1 min-w-0">
            <div className="font-semibold text-sm truncate" style={{ color: 'var(--text-primary)' }}>{user?.full_name}</div>
            <div className="text-xs truncate" style={{ color: 'var(--text-muted)' }}>{user?.email || user?.employee_id}</div>
            <span className={`badge badge-blue mt-1`} style={{ fontSize: 10 }}>
              {roleInfo.label || role}
            </span>
          </div>
        </div>
      </div>

      {/* Exchange Rates */}
      {rates && (
        <div className="px-4 py-3 border-b" style={{ borderColor: 'var(--border-base)' }}>
          <div className="text-xs font-semibold mb-2" style={{ color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '0.06em' }}>
            Live Exchange Rates
          </div>
          <div className="grid grid-cols-2 gap-2">
            {[['USD', rates.USD_IDR], ['SGD', rates.SGD_IDR], ['EUR', rates.EUR_IDR], ['MYR', rates.MYR_IDR]].filter(([,v]) => v).map(([cur, val]) => (
              <div key={cur} className="rounded-lg p-2 text-center" style={{ background: 'var(--bg-surface-2)' }}>
                <div className="text-xs font-bold" style={{ color: 'var(--text-muted)' }}>{cur}/IDR</div>
                <div className="text-xs font-semibold mt-0.5" style={{ color: 'var(--text-primary)' }}>
                  {Number(val).toLocaleString('id-ID', { maximumFractionDigits: 0 })}
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Actions */}
      <div className="p-2">
        <div className="dropdown-item rounded-xl" onClick={() => { navigate('/profile'); onClose(); }}>
          <User style={{ width: 15, height: 15 }} />
          <span>Edit Profil</span>
        </div>
        <div className="dropdown-item rounded-xl" onClick={() => { navigate('/profile?tab=security'); onClose(); }}>
          <Key style={{ width: 15, height: 15 }} />
          <span>Keamanan & Password</span>
        </div>
        <div className="dropdown-item rounded-xl" onClick={() => { toggleTheme(); }}>
          {theme === 'dark' ? <Sun style={{ width: 15, height: 15 }} /> : <Moon style={{ width: 15, height: 15 }} />}
          <span>{theme === 'dark' ? 'Light Mode' : 'Dark Mode'}</span>
        </div>
        <div className="dropdown-item rounded-xl" onClick={() => setLocale(locale === 'id' ? 'en' : 'id')}>
          <Languages style={{ width: 15, height: 15 }} />
          <span>{locale === 'id' ? 'Switch to English' : 'Ganti ke Indonesian'}</span>
        </div>
        <div className="dropdown-divider" />
        <div className="dropdown-item danger rounded-xl" onClick={() => { onLogout(); onClose(); }}>
          <LogOut style={{ width: 15, height: 15 }} />
          <span>Sign Out</span>
        </div>
      </div>
    </div>
  );
}

// ── Notification Panel ────────────────────────────────────────
function NotifPanel({ notifs, onClose, onMarkAll }) {
  return (
    <div
      className="dropdown-menu"
      style={{ width: 340, position: 'absolute', right: 0, top: 'calc(100% + 8px)', zIndex: 100 }}
      onClick={e => e.stopPropagation()}
    >
      <div className="flex items-center justify-between px-4 py-3 border-b" style={{ borderColor: 'var(--border-base)' }}>
        <span className="font-semibold text-sm" style={{ color: 'var(--text-primary)' }}>Notifikasi</span>
        <button className="btn btn-ghost btn-sm" onClick={onMarkAll} style={{ fontSize: 11 }}>Tandai Semua Dibaca</button>
      </div>
      <div style={{ maxHeight: 320, overflowY: 'auto' }}>
        {notifs.length === 0 ? (
          <div className="py-10 text-center" style={{ color: 'var(--text-muted)', fontSize: 13 }}>
            <Bell style={{ width: 24, height: 24, margin: '0 auto 8px', opacity: 0.3 }} />
            Tidak ada notifikasi
          </div>
        ) : notifs.map(n => (
          <div
            key={n.id}
            className="dropdown-item"
            style={{ opacity: n.is_read ? 0.6 : 1, alignItems: 'flex-start', gap: 10, padding: '12px 16px' }}
          >
            <div className="w-2 h-2 rounded-full mt-1.5 flex-shrink-0"
              style={{ background: n.is_read ? 'var(--border-strong)' : 'var(--brand-500)' }} />
            <div className="flex-1 min-w-0">
              <div className="font-semibold text-xs" style={{ color: 'var(--text-primary)' }}>{n.title}</div>
              <div className="text-xs mt-0.5" style={{ color: 'var(--text-muted)' }}>{n.message}</div>
            </div>
          </div>
        ))}
      </div>
      <div className="p-2 border-t" style={{ borderColor: 'var(--border-base)' }}>
        <Link to="/notifications" className="btn btn-ghost btn-sm w-full" onClick={onClose} style={{ justifyContent: 'center' }}>
          Lihat Semua
        </Link>
      </div>
    </div>
  );
}

// ── Main Layout ───────────────────────────────────────────────
export default function CRMLayout({ children }) {
  const { user, logout } = useAuth();
  const { theme } = useUI();
  const location = useLocation();
  const navigate = useNavigate();

  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [collapsed, setCollapsed] = useState(() => {
    try { return localStorage.getItem('crm_sidebar_collapsed') === 'true'; } catch { return false; }
  });
  const [notifs, setNotifs] = useState([]);
  const [rates, setRates] = useState(null);
  const [profileOpen, setProfileOpen] = useState(false);
  const [notifOpen, setNotifOpen] = useState(false);
  const [searchOpen, setSearchOpen] = useState(false);
  const [searchQ, setSearchQ] = useState('');

  const profileRef = useRef(null);
  const notifRef = useRef(null);

  const unread = notifs.filter(n => !n.is_read).length;

  useEffect(() => {
    notifAPI.getAll().then(r => setNotifs(r.data.data || [])).catch(() => {});
    exchangeAPI.getRates().then(r => setRates(r.data.data)).catch(() => {});
  }, []);

  useEffect(() => {
    try { localStorage.setItem('crm_sidebar_collapsed', String(collapsed)); } catch {}
  }, [collapsed]);

  useEffect(() => {
    const handler = (e) => {
      if (profileRef.current && !profileRef.current.contains(e.target)) setProfileOpen(false);
      if (notifRef.current && !notifRef.current.contains(e.target)) setNotifOpen(false);
    };
    document.addEventListener('mousedown', handler);
    return () => document.removeEventListener('mousedown', handler);
  }, []);

  // Keyboard shortcut: Cmd/Ctrl+K for search
  useEffect(() => {
    const handler = (e) => {
      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
        e.preventDefault();
        setSearchOpen(v => !v);
      }
      if (e.key === 'Escape') {
        setSearchOpen(false);
        setProfileOpen(false);
        setNotifOpen(false);
      }
    };
    document.addEventListener('keydown', handler);
    return () => document.removeEventListener('keydown', handler);
  }, []);

  const handleLogout = useCallback(() => {
    logout();
    toast.success('Logout berhasil');
    navigate('/login');
  }, [logout, navigate]);

  // Get current page info
  const allItems = NAV_GROUPS.flatMap(g => g.items);
  const currentItem = allItems.find(item =>
    location.pathname === item.path || location.pathname.startsWith(item.path + '/')
  );

  return (
    <div
      className="flex overflow-hidden"
      style={{ height: '100vh', background: 'var(--bg-base)' }}
    >
      {/* Sidebar */}
      <Sidebar
        user={user}
        collapsed={collapsed}
        onCollapse={() => setCollapsed(v => !v)}
        mobileOpen={sidebarOpen}
        onMobileClose={() => setSidebarOpen(false)}
        location={location}
        onLogout={handleLogout}
      />

      {/* Main area */}
      <div className="flex flex-col flex-1 min-w-0 overflow-hidden">

        {/* Topbar */}
        <header className="topbar px-4 lg:px-6 gap-3 flex-shrink-0">
          {/* Left: toggle + breadcrumb */}
          <div className="flex items-center gap-3 flex-1 min-w-0">
            {/* Mobile menu */}
            <button
              onClick={() => setSidebarOpen(true)}
              className="btn btn-ghost btn-icon lg:hidden"
            >
              <Menu style={{ width: 18, height: 18 }} />
            </button>

            {/* Desktop collapse */}
            <button
              onClick={() => setCollapsed(v => !v)}
              className="btn btn-ghost btn-icon hidden lg:flex"
              title={collapsed ? 'Perlebar Sidebar' : 'Perkecil Sidebar'}
            >
              {collapsed
                ? <PanelLeftOpen style={{ width: 17, height: 17 }} />
                : <PanelLeftClose style={{ width: 17, height: 17 }} />
              }
            </button>

            {/* Breadcrumb */}
            <div className="hidden sm:flex items-center gap-2 min-w-0">
              <span style={{ color: 'var(--text-muted)', fontSize: 13 }}>Abnan CRM</span>
              <ChevronRight style={{ width: 14, height: 14, color: 'var(--text-muted)', flexShrink: 0 }} />
              <span className="font-semibold truncate" style={{ color: 'var(--text-primary)', fontSize: 13 }}>
                {currentItem?.label || 'Dashboard'}
              </span>
            </div>

            <div className="sm:hidden font-semibold" style={{ color: 'var(--text-primary)', fontSize: 15 }}>
              {currentItem?.label || 'Dashboard'}
            </div>
          </div>

          {/* Right: search + notif + profile */}
          <div className="flex items-center gap-2 flex-shrink-0">

            {/* Search trigger */}
            <button
              onClick={() => setSearchOpen(true)}
              className="btn btn-secondary btn-sm hidden md:flex items-center gap-2"
              style={{ color: 'var(--text-muted)', fontWeight: 500 }}
            >
              <Search style={{ width: 14, height: 14 }} />
              <span>Cari...</span>
              <kbd className="px-1.5 py-0.5 rounded text-xs" style={{
                background: 'var(--bg-surface-2)', border: '1px solid var(--border-base)',
                color: 'var(--text-muted)', fontFamily: 'inherit', fontSize: 10
              }}>⌘K</kbd>
            </button>

            <button
              onClick={() => setSearchOpen(true)}
              className="btn btn-ghost btn-icon md:hidden"
            >
              <Search style={{ width: 17, height: 17 }} />
            </button>

            {/* Notifications */}
            <div className="relative" ref={notifRef}>
              <button
                onClick={() => { setNotifOpen(v => !v); setProfileOpen(false); }}
                className="btn btn-ghost btn-icon relative"
              >
                <Bell style={{ width: 17, height: 17 }} />
                {unread > 0 && (
                  <span
                    className="absolute top-1.5 right-1.5 w-2 h-2 rounded-full"
                    style={{ background: 'var(--danger-500)' }}
                  >
                    <span className="absolute inset-0 rounded-full animate-ping" style={{ background: 'var(--danger-500)', opacity: 0.6 }} />
                  </span>
                )}
              </button>
              {notifOpen && (
                <NotifPanel
                  notifs={notifs}
                  onClose={() => setNotifOpen(false)}
                  onMarkAll={() => setNotifs(notifs.map(n => ({ ...n, is_read: true })))}
                />
              )}
            </div>

            {/* Live indicator */}
            <div className="hidden lg:flex items-center gap-1.5 px-3 py-1.5 rounded-lg" style={{ background: 'var(--bg-surface-2)', border: '1px solid var(--border-base)' }}>
              <span className="relative flex h-2 w-2">
                <span className="animate-ping absolute inline-flex h-full w-full rounded-full opacity-75" style={{ background: 'var(--success-500)' }} />
                <span className="relative inline-flex rounded-full h-2 w-2" style={{ background: 'var(--success-500)' }} />
              </span>
              <span style={{ fontSize: 11, fontWeight: 600, color: 'var(--text-muted)' }}>Live</span>
            </div>

            {/* Profile */}
            <div className="relative" ref={profileRef}>
              <button
                onClick={() => { setProfileOpen(v => !v); setNotifOpen(false); }}
                className="flex items-center gap-2 px-2 py-1.5 rounded-xl transition-all"
                style={{
                  background: profileOpen ? 'var(--bg-surface-2)' : 'transparent',
                  border: '1px solid transparent',
                  borderColor: profileOpen ? 'var(--border-base)' : 'transparent',
                }}
              >
                <div
                  className="w-7 h-7 rounded-lg flex items-center justify-center text-white text-xs font-bold"
                  style={{ background: 'linear-gradient(135deg, #3a71f6, #7c3aed)' }}
                >
                  {getInitials(user?.full_name)}
                </div>
                <div className="hidden md:block text-left">
                  <div className="text-xs font-semibold leading-tight" style={{ color: 'var(--text-primary)' }}>
                    {user?.full_name?.split(' ')[0]}
                  </div>
                </div>
                <ChevronDown style={{ width: 13, height: 13, color: 'var(--text-muted)', transform: profileOpen ? 'rotate(180deg)' : 'none', transition: 'transform 200ms' }} />
              </button>

              {profileOpen && (
                <ProfileDropdown
                  user={user}
                  rates={rates}
                  onLogout={handleLogout}
                  onClose={() => setProfileOpen(false)}
                />
              )}
            </div>
          </div>
        </header>

        {/* Content */}
        <main
          className="flex-1 overflow-y-auto overflow-x-hidden"
          style={{ padding: '24px', paddingTop: 20 }}
          id="main-content"
        >
          <div className="mx-auto max-w-7xl animate-page-enter">
            {children}
          </div>
        </main>
      </div>

      {/* Search Modal */}
      {searchOpen && (
        <div className="modal-overlay" onClick={() => setSearchOpen(false)}>
          <div
            className="modal-content"
            style={{ maxWidth: 560, width: '100%', maxHeight: '70vh' }}
            onClick={e => e.stopPropagation()}
          >
            <div className="p-4 flex items-center gap-3 border-b" style={{ borderColor: 'var(--border-base)' }}>
              <Search style={{ width: 18, height: 18, color: 'var(--text-muted)', flexShrink: 0 }} />
              <input
                className="input-base"
                autoFocus
                placeholder="Cari menu, customer, invoice..."
                value={searchQ}
                onChange={e => setSearchQ(e.target.value)}
                style={{ border: 'none', background: 'transparent', padding: '4px 0', boxShadow: 'none', fontSize: 15 }}
              />
              <button
                onClick={() => setSearchOpen(false)}
                className="btn btn-ghost btn-icon btn-sm"
              >
                <X style={{ width: 15, height: 15 }} />
              </button>
            </div>
            <div className="p-4 overflow-y-auto flex-1">
              {searchQ.trim() === '' ? (
                <div>
                  <div className="text-xs font-semibold mb-3 uppercase" style={{ color: 'var(--text-muted)', letterSpacing: '0.06em' }}>
                    Navigasi Cepat
                  </div>
                  <div className="space-y-1">
                    {allItems.filter(i => i.roles.includes(user?.role)).slice(0, 8).map(item => {
                      const Icon = item.icon;
                      return (
                        <Link
                          key={item.path}
                          to={item.path}
                          onClick={() => setSearchOpen(false)}
                          className="flex items-center gap-3 p-2.5 rounded-xl"
                          style={{ color: 'var(--text-secondary)', textDecoration: 'none', transition: 'background 150ms' }}
                          onMouseEnter={e => e.currentTarget.style.background = 'var(--bg-surface-2)'}
                          onMouseLeave={e => e.currentTarget.style.background = 'transparent'}
                        >
                          <Icon style={{ width: 15, height: 15, flexShrink: 0 }} />
                          <span style={{ fontSize: 14 }}>{item.label}</span>
                        </Link>
                      );
                    })}
                  </div>
                </div>
              ) : (
                <div className="space-y-1">
                  {allItems.filter(i =>
                    i.roles.includes(user?.role) &&
                    i.label.toLowerCase().includes(searchQ.toLowerCase())
                  ).map(item => {
                    const Icon = item.icon;
                    return (
                      <Link
                        key={item.path}
                        to={item.path}
                        onClick={() => setSearchOpen(false)}
                        className="flex items-center gap-3 p-2.5 rounded-xl"
                        style={{ color: 'var(--text-secondary)', textDecoration: 'none', transition: 'background 150ms' }}
                        onMouseEnter={e => e.currentTarget.style.background = 'var(--bg-surface-2)'}
                        onMouseLeave={e => e.currentTarget.style.background = 'transparent'}
                      >
                        <Icon style={{ width: 15, height: 15, flexShrink: 0 }} />
                        <span style={{ fontSize: 14 }}>{item.label}</span>
                      </Link>
                    );
                  })}
                  {allItems.filter(i =>
                    i.roles.includes(user?.role) &&
                    i.label.toLowerCase().includes(searchQ.toLowerCase())
                  ).length === 0 && (
                    <div className="text-center py-6" style={{ color: 'var(--text-muted)', fontSize: 14 }}>
                      Tidak ada hasil untuk "{searchQ}"
                    </div>
                  )}
                </div>
              )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
